css:
.loader {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #7c3aed);
  background: 
    conic-gradient(from -135deg at 100% 50%,var(--loader-color, #7c3aed) 90deg,#0000 0) text no-repeat,
    conic-gradient(from -135deg at 1lh  50%,#0000 90deg,var(--loader-color, #7c3aed) 0) text no-repeat;
  animation: l6 2s linear infinite;
}
.loader:before {
  content: "Loading";
}
@keyframes l6 {
  0%     {background-size: 0                200%;background-position:0 0   ,100% 0   }
  50%    {background-size: calc(60% + .5lh) 200%;background-position:0 0   ,100% 0   }
  50.01% {background-size: calc(60% + .5lh) 200%;background-position:0 100%,100% 100%}
  100%   {background-size: 0                200%;background-position:0 100%,100% 100%}
}
